    /**
     * Checks if it's possible to construct nums2 such that all elements have the target parity P_target (0 for even, 1 for odd).
     * 
     * @param nums1 The input array.
     * @param targetParity The desired parity for all elements of nums2.
     * @param counts A tuple (C0, C1) where C0 is count of even numbers, C1 is count of odd numbers.
     * @return True if targetParity is achievable, false otherwise.
     */
    def check(nums1: Array[Long], targetParity: Int, counts: (Int, Int)): Boolean = {
        val n = nums1.length
        val (C0, C1) = counts

        for (i <- 0 until n) {
            val p_i = (nums1(i) % 2).toInt // Parity of nums1[i]
            var satisfied = false

            // Option A: nums2[i] = nums1[i]
            if (p_i == targetParity) {
                satisfied = true
            } else {
                // Option B: nums2[i] = nums1[i] - nums1[j], j != i
                // Required parity R for nums1[j] such that p_i + R == targetParity (mod 2)
                val R = (targetParity - p_i + 2) % 2

                var optionB_possible = false

                if (R == 0) { // We need an even nums1[j]
                    // If nums1[i] itself is even (p_i=0), we need C0 >= 2.
                    // If nums1[i] is odd (p_i=1), we need C0 >= 1.
                    if (p_i == 0) { // p_i == R
                        if (C0 >= 2) optionB_possible = true
                    } else { // p_i != R
                        if (C0 >= 1) optionB_possible = true
                    }
                } else { // R == 1. We need an odd nums1[j]
                    // If nums1[i] itself is odd (p_i=1), we need C1 >= 2.
                    // If nums1[i] is even (p_i=0), we need C1 >= 1.
                    if (p_i == 1) { // p_i == R
                        if (C1 >= 2) optionB_possible = true
                    } else { // p_i != R
                        if (C1 >= 1) optionB_possible = true
                    }
                }

                if (optionB_possible) {
                    satisfied = true
                }
            }

            if (!satisfied) {
                return false
            }
        }
        true
    }


