        val n = nums1.length

        if (n == 0) return true // Should not happen based on constraints
        if (n == 1) return true

        var C0 = 0 // Count of even numbers
        var C1 = 0 // Count of odd numbers

        for (x <- nums1) {
            if (x % 2 == 0) {
