    val cEven = n - cOdd

    // Check if all elements can be made EVEN (P_T = 0)
    // This requires that if there are odd numbers (cOdd > 0), there must be at least two,
    // so that any single odd number can be transformed into an even number 
    // by subtracting another odd number.
    // If cOdd = 1, the unique odd number cannot be transformed into even.
    val possibleEven = (cOdd != 1)

    // Check if all elements can be made ODD (P_T = 1)
    // If there is at least one odd number (cOdd >= 1), any even number can be made odd
    // by subtracting the odd number.
    // If all numbers are odd (cEven = 0), it is trivially possible.
    val possibleOdd = (cOdd >= 1 || cEven == 0)

    possibleEven || possibleOdd
}
